#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int L; scanf("%d", &L);
        static char s[100005];
        scanf("%s", s);
        int good = 0; int ans = 0;
        for(int i=0;i<L;i++){
            if(s[i]=='1') good++;
            if(2*good >= i+1){ ans = 1; break; }
        }
        puts(ans?"YES":"NO");
    }
    return 0;
}

