const T = Number(input[idx++]);
let res = [];
for (let tc = 0; tc < T; tc++) {
  const L = Number(input[idx++]);
  const s = input[idx++];
  let good = 0;
  let ok = false;
  for (let i = 0; i < L; i++) {
    if (s[i] === '1') good++;
    if (2 * good >= i + 1) { ok = true; break; }
  }
  res.push(ok ? 'YES' : 'NO');
}
